CREATE TABLE public.waitlist_emails (id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY, email TEXT NOT NULL, created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now()); GRANT INSERT ON public.waitlist_emails TO anon, authenticated; GRANT ALL ON public.waitlist_emails TO service_role; ALTER TABLE public.waitlist_emails ENABLE ROW LEVEL SECURITY; CREATE POLICY "Anyone can join waitlist" ON public.waitlist_emails FOR INSERT TO anon, authenticated WITH CHECK (true);